INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '100fb8fd-6866-467d-8059-8951556f615a',
  '00000000-0000-0000-0000-000000000001',
  $escape$Vault Cloud Security — Securing Your AWS Resources with Vault$escape$,
  $escape$When securing your AWS resources with Vault, it's essential to use network security groups, NACLs, and private subnets to control access. Use Vault's AWS provider to create and manage these resources. For example, you can use the `vault aws iam get-user` command to retrieve the IAM user credentials, and then use a network security group to restrict access to your EC2 instance. Additionally, use a bastion host to access your private subnet securely.$escape$,
  NULL,
  NULL,
